import React from "react";
import { graphql } from "gatsby";
import { MDXProvider } from "@mdx-js/react";
import { MDXRenderer } from "gatsby-plugin-mdx";
import { Link } from "gatsby";

import WebPage from "../components/webPage/WebPage";
import PageArticle from "../components/pageArticle/PageArticle";
import Emoji from "../components/emoji/Emoji";

const shortcodes = { Link, Emoji }; // Provide common components here

export default function ProjectTemplate({ data: { mdx } }) {
  return (
    <WebPage>
      <PageArticle>
        <Link to="/projects">Back to projects</Link>

        <MDXProvider components={shortcodes}>
          <MDXRenderer>{mdx.body}</MDXRenderer>
        </MDXProvider>
      </PageArticle>
    </WebPage>
  );
}

export const pageQuery = graphql`
  query Projects($id: String) {
    mdx(id: { eq: $id }, fields: { collection: { eq: "projects" } }) {
      id
      body
      frontmatter {
        title
      }
    }
  }
`;

